Here's a complete implementation:

**XAML (ItemsPage.xaml)**
```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.ItemsPage">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    IsRefreshing="{Binding IsRefreshing}"
                    RemainingItemsThreshold="0">

        <CollectionView.Header>
            <RefreshView Command="{Binding RefreshCommand}"
                         IsRefreshing="{Binding IsRefreshing}">
                <!-- wrapping the CollectionView body isn't needed;
                     see alternative below -->
            </RefreshView>
        </CollectionView.Header>

        <CollectionView.ItemTemplate>
            <DataTemplate>
                <VerticalStackLayout Padding="10">
                    <Label Text="{Binding Name}" FontSize="18" />
                    <Label Text="{Binding Description}" FontSize="14"
                           TextColor="Gray" />
                </VerticalStackLayout>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>

</ContentPage>
```

The cleaner pattern is to wrap the **entire CollectionView** in a `RefreshView`:

```xml
<RefreshView Command="{Binding RefreshCommand}"
             IsRefreshing="{Binding IsRefreshing}">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}">
        <CollectionView.ItemTemplate>
            <DataTemplate>
                <VerticalStackLayout Padding="10">
                    <Label Text="{Binding Name}" FontSize="18" />
                    <Label Text="{Binding Description}" FontSize="14"
                           TextColor="Gray" />
                </VerticalStackLayout>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>

</RefreshView>
```

**ViewModel (ItemsViewModel.cs)**
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [ObservableProperty]
    private ObservableCollection<Item> _items = new();

    [ObservableProperty]
    private bool _isRefreshing;

    [ObservableProperty]
    private Item? _selectedItem;

    // Fires automatically when SelectedItem changes (CommunityToolkit naming convention)
    partial void OnSelectedItemChanged(Item? value)
    {
        if (value is null) return;

        // Navigate, then clear selection so the user can re-select the same row
        _nav.NavigateAsync(nameof(DetailPage), new Dictionary<string, object>
        {
            { "Item", value }
        });

        SelectedItem = null;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items = new ObservableCollection<Item>(data);
        }
        finally
        {
            IsRefreshing = false;   // stops the spinner
        }
    }
}
```

### Key binding relationships

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `ItemsSource` | `Items` (ObservableCollection) | Drives the list |
| `SelectionMode="Single"` | — | Enables tap-to-select |
| `SelectedItem` | `SelectedItem` (two-way by default) | Triggers `OnSelectedItemChanged` |
| `RefreshView.Command` | `RefreshCommand` | Generated by `[RelayCommand]` on `RefreshAsync` |
| `RefreshView.IsRefreshing` | `IsRefreshing` | Controls the pull-to-refresh spinner |

**Important details:**
- Set `IsRefreshing = false` in `finally` — otherwise the spinner never stops.
- Reset `SelectedItem = null` after navigating so the same row can be tapped again.
- `RefreshView` must wrap `CollectionView`, not the other way around.
- Uses **CommunityToolkit.Mvvm** source generators (`[ObservableProperty]`, `[RelayCommand]`).
